import{_ as e,o,c as t,Q as i}from"./chunks/framework.6a72df8e.js";const m=JSON.parse('{"title":"Arduino学习笔记","description":"","frontmatter":{"title":"Arduino学习笔记","date":"2023-06-02T01:38:25.000Z","tags":["esp32","arduino"]},"headers":[{"level":2,"title":"pinMode(pin, mode)","slug":"pinmode-pin-mode","link":"#pinmode-pin-mode","children":[]}],"relativePath":"src/esp32/arduino/Arduino学习笔记.md","lastUpdated":1700455155000}'),n={name:"src/esp32/arduino/Arduino学习笔记.md"},s=i('<h1 id="arduino学习笔记" tabindex="-1">Arduino学习笔记 <a class="header-anchor" href="#arduino学习笔记" aria-hidden="true">#</a></h1><h2 id="pinmode-pin-mode" tabindex="-1">pinMode(pin, mode) <a class="header-anchor" href="#pinmode-pin-mode" aria-hidden="true">#</a></h2><p><strong>mode</strong><sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>:</p><p>INPUT sets the GPIO as input without pullup or pulldown (high impedance).<sup class="footnote-ref"><a href="#fn2" id="fnref2">[2]</a></sup></p><p>OUTPUT sets the GPIO as output/read mode.</p><p>INPUT_PULLDOWN sets the GPIO as input with the internal pulldown.</p><p>INPUT_PULLUP sets the GPIO as input with the internal pullup.</p><ul><li>output</li></ul><p>当引脚设置为输出（OUTPUT）模式时，引脚为低阻抗状态。这意味着Arduino可以向其它电路元器件提供电流。也就是说，Arduino引脚在输出（OUTPUT）模式下可以点亮LED或者驱动电机。（如果被驱动的电机需要超过40mA的电流，Arduino将需要三极管或其它辅助元件来驱动他们。）</p><ul><li>input</li></ul><p>当引脚设置为输入（INPUT）模式时，引脚为高阻抗状态（100兆欧）。此时该引脚可用于读取传感器信号或开关信号。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>当Arduino引脚设置为输入（INPUT）模式或者输入上拉（INPUT_PULLUP）模式，请勿将该引脚与负压或者高于5V的电压相连，否则可能会损坏Arduino控制器。</p></div><ul><li>input_pullup</li></ul><p>Arduino 微控制器自带内部上拉电阻。如果你需要使用该内部上拉电阻，可以通过pinMode()将引脚设置为输入上拉（INPUT_PULLUP）模式。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>当Arduino引脚设置为输入（INPUT）模式或者输入上拉（INPUT_PULLUP）模式，请勿将该引脚与负压或者高于5V的电压相连，否则可能会损坏Arduino控制器。</p></div><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p><a href="http://www.taichi-maker.com/homepage/reference-index/arduino-code-reference/pinmode/" target="_blank" rel="noreferrer">http://www.taichi-maker.com/homepage/reference-index/arduino-code-reference/pinmode/</a> <a href="#fnref1" class="footnote-backref">↩︎</a></p></li><li id="fn2" class="footnote-item"><p><a href="https://espressif-docs.readthedocs-hosted.com/projects/arduino-esp32/en/latest/api/gpio.html" target="_blank" rel="noreferrer">https://espressif-docs.readthedocs-hosted.com/projects/arduino-esp32/en/latest/api/gpio.html</a> <a href="#fnref2" class="footnote-backref">↩︎</a></p></li></ol></section>',17),r=[s];function a(p,d,l,c,u,h){return o(),t("div",null,r)}const _=e(n,[["render",a]]);export{m as __pageData,_ as default};
